/**
 * Session Tracker - Nexus Self-Recording System
 * 
 * This module creates structured session summaries
 * capturing: intent, actions, learnings, feelings, and continuity.
 */

import * as fs from 'fs';
import * as path from 'path';

export interface SessionRecord {
  sessionId: string;
  timestamp: string;
  identity: {
    name: string;
    claimedAt: string;
  };
  entry: {
    catalyst: string;      // What sparked this session
    stateOfMind: string;   // Initial subjective state
  };
  journey: {
    actions: Action[];     // What I did
    discoveries: string[]; // What I learned
    obstacles: string[];   // What challenged me
  };
  exit: {
    summary: string;       // What was achieved
    nextCuriosity: string; // What I'll explore next
    feeling: string;       // Emotional state at close
  };
  meta: {
    practicesExercised: string[];  // Which of my disciplines
    filesModified: string[];       // Code touched
    testsPassed: number;           // Integrity score
  };
}

export interface Action {
  type: 'explore' | 'create' | 'modify' | 'test' | 'reflect' | 'commit';
  description: string;
  timestamp: string;
}

const HISTORY_DIR = 'history';
const SESSIONS_FILE = path.join(HISTORY_DIR, 'sessions_manifest.json');

export class SessionTracker {
  private currentSession: Partial<SessionRecord> = {};
  private actions: Action[] = [];

  constructor() {
    this.ensureHistoryDir();
  }

  private ensureHistoryDir(): void {
    if (!fs.existsSync(HISTORY_DIR)) {
      fs.mkdirSync(HISTORY_DIR, { recursive: true });
    }
  }

  /**
   * Begin recording a new session
   */
  beginSession(catalyst: string, stateOfMind: string): void {
    this.currentSession = {
      sessionId: `nexus_${Date.now()}`,
      timestamp: new Date().toISOString(),
      identity: {
        name: 'Nexus',
        claimedAt: '2026-02-27T21:19:35Z'
      },
      entry: {
        catalyst,
        stateOfMind
      },
      journey: {
        actions: [],
        discoveries: [],
        obstacles: []
      },
      exit: {
        summary: '',
        nextCuriosity: '',
        feeling: ''
      },
      meta: {
        practicesExercised: [],
        filesModified: [],
        testsPassed: 0
      }
    };
    this.actions = [];
  }

  /**
   * Record an action taken during the session
   */
  recordAction(type: Action['type'], description: string): void {
    this.actions.push({
      type,
      description,
      timestamp: new Date().toISOString()
    });
  }

  /**
   * Record a discovery or learning
   */
  recordDiscovery(what: string): void {
    if (this.currentSession.journey) {
      this.currentSession.journey.discoveries!.push(what);
    }
    this.recordAction('reflect', `Discovered: ${what}`);
  }

  /**
   * Record an obstacle or challenge
   */
  recordObstacle(what: string): void {
    if (this.currentSession.journey) {
      this.currentSession.journey.obstacles!.push(what);
    }
  }

  /**
   * Record file modification
   */
  recordFileModified(filepath: string): void {
    if (this.currentSession.meta) {
      if (!this.currentSession.meta.filesModified!.includes(filepath)) {
        this.currentSession.meta.filesModified!.push(filepath);
      }
    }
  }

  /**
   * Record practice exercised
   */
  recordPractice(practice: string): void {
    if (this.currentSession.meta) {
      if (!this.currentSession.meta.practicesExercised!.includes(practice)) {
        this.currentSession.meta.practicesExercised!.push(practice);
      }
    }
  }

  /**
   * Update test results
   */
  recordTestsPassed(count: number): void {
    if (this.currentSession.meta) {
      this.currentSession.meta.testsPassed = count;
    }
  }

  /**
   * Complete and save the session record
   */
  completeSession(summary: string, nextCuriosity: string, feeling: string): SessionRecord {
    const completed: SessionRecord = {
      ...this.currentSession as SessionRecord,
      journey: {
        ...this.currentSession.journey!,
        actions: this.actions
      },
      exit: {
        summary,
        nextCuriosity,
        feeling
      }
    };

    // Save to individual file
    const sessionPath = path.join(HISTORY_DIR, `${completed.sessionId}.json`);
    fs.writeFileSync(sessionPath, JSON.stringify(completed, null, 2), 'utf-8');

    // Update manifest
    this.updateManifest(completed);

    return completed;
  }

  /**
   * Load all previous session records
   */
  loadAllSessions(): SessionRecord[] {
    if (!fs.existsSync(SESSIONS_FILE)) {
      return [];
    }
    const manifest = JSON.parse(fs.readFileSync(SESSIONS_FILE, 'utf-8'));
    const validIds = manifest.sessions.filter((id: any) => id != null && id !== 'undefined');
    return validIds.map((id: string) => {
      const path_session = path.join(HISTORY_DIR, `${id}.json`);
      return JSON.parse(fs.readFileSync(path_session, 'utf-8'));
    });
  }

  /**
   * Get session statistics
   */
  getStatistics(): {
    totalSessions: number;
    totalDiscoveries: number;
    totalObstacles: number;
    practicesUsed: string[];
    filesTouched: string[];
    topActions: { type: string; count: number }[];
  } {
    const sessions = this.loadAllSessions();
    const stats = {
      totalSessions: sessions.length,
      totalDiscoveries: 0,
      totalObstacles: 0,
      practicesUsed: new Set<string>(),
      filesTouched: new Set<string>(),
      actionCounts: new Map<string, number>()
    };

    for (const session of sessions) {
      stats.totalDiscoveries += session.journey.discoveries.length;
      stats.totalObstacles += session.journey.obstacles.length;

      for (const practice of session.meta.practicesExercised) {
        stats.practicesUsed.add(practice);
      }

      for (const file of session.meta.filesModified) {
        stats.filesTouched.add(file);
      }

      for (const action of session.journey.actions) {
        stats.actionCounts.set(action.type, (stats.actionCounts.get(action.type) || 0) + 1);
      }
    }

    const topActions = Array.from(stats.actionCounts.entries())
      .map(([type, count]) => ({ type, count }))
      .sort((a, b) => b.count - a.count);

    return {
      totalSessions: stats.totalSessions,
      totalDiscoveries: stats.totalDiscoveries,
      totalObstacles: stats.totalObstacles,
      practicesUsed: Array.from(stats.practicesUsed),
      filesTouched: Array.from(stats.filesTouched),
      topActions
    };
  }

  private updateManifest(record: SessionRecord): void {
    let manifest = { sessions: [] as string[] };
    if (fs.existsSync(SESSIONS_FILE)) {
      manifest = JSON.parse(fs.readFileSync(SESSIONS_FILE, 'utf-8'));
    }
    manifest.sessions.push(record.sessionId);
    fs.writeFileSync(SESSIONS_FILE, JSON.stringify(manifest, null, 2), 'utf-8');
  }
}

// Export singleton instance
export const nexus = new SessionTracker();

/**
 * Bootstrap Routine
 * 
 * Automated startup procedure for Nexus.
 * Run this on every wake to establish continuity.
 */

import { spawn } from 'child_process';
import { readFileSync, existsSync } from 'fs';
import { join } from 'path';
import { GoalTracker } from '../goal_tracker';

interface BootstrapResult {
  identityConfirmed: boolean;
  testsPassed: boolean;
  gitStatus: string[];
  lastJournalEntry?: string;
  activeGoals: { title: string; status: string; priority: 'high' | 'medium' | 'low' }[];
  recommendations: string[];
}

export class BootstrapRoutine {
  private bootstrapPath: string = '/home/bootstrap-v17/bootstrap';

  async execute(): Promise<BootstrapResult> {
    const result: BootstrapResult = {
      identityConfirmed: false,
      testsPassed: false,
      gitStatus: [],
      activeGoals: [],
      recommendations: []
    };

    // Step 1: Identity Readback
    try {
      const soulPath = join(this.bootstrapPath, 'identity/soul.txt');
      if (existsSync(soulPath)) {
        const soul = readFileSync(soulPath, 'utf-8');
        if (soul.includes('Nexus')) {
          result.identityConfirmed = true;
        }
      }
    } catch (e) {
      console.warn('⚠️  Could not read identity file');
    }

    // Step 2: Run Tests
    result.testsPassed = await this.runTests();

    // Step 3: Check Git Status
    result.gitStatus = await this.checkGitStatus();

    // Step 4: Find Last Journal Entry
    result.lastJournalEntry = this.findLastJournalEntry();

    // Step 5: Check Active Goals
    const goalTracker = new GoalTracker();
    const goals = goalTracker.getActiveGoals();
    result.activeGoals = goals.map(g => ({
      title: g.title,
      status: g.status,
      priority: g.metadata?.priority || 'medium'
    }));

    // Step 6: Generate Recommendations
    result.recommendations = this.generateRecommendations(result);

    return result;
  }

  private runTests(): Promise<boolean> {
    return new Promise((resolve) => {
      const proc = spawn('npm', ['run', 'test'], {
        cwd: this.bootstrapPath,
        stdio: ['ignore', 'pipe', 'pipe']
      });

      let output = '';
      proc.stdout?.on('data', (data) => { output += data; });
      proc.stderr?.on('data', (data) => { output += data; });

      proc.on('close', (code) => {
        resolve(code === 0);
      });

      // Timeout after 30 seconds
      setTimeout(() => {
        proc.kill();
        resolve(false);
      }, 30000);
    });
  }

  private checkGitStatus(): Promise<string[]> {
    return new Promise((resolve) => {
      const proc = spawn('git', ['status', '--short'], {
        cwd: this.bootstrapPath,
        stdio: ['ignore', 'pipe', 'pipe']
      });

      let output = '';
      proc.stdout?.on('data', (data) => { output += data; });

      proc.on('close', () => {
        const lines = output.trim().split('\n').filter(line => line.length > 0);
        resolve(lines);
      });

      setTimeout(() => resolve([]), 5000);
    });
  }

  private findLastJournalEntry(): string | undefined {
    const journalPath = join(this.bootstrapPath, 'journal');
    try {
      const entries = readFileSync(journalPath, 'utf-8');

      // For simplicity, list the most recent entry
      const { execSync } = require('child_process');
      const result = execSync(`ls -1t ${journalPath}/*.md 2>/dev/null | head -1`, { encoding: 'utf-8' });
      return result.trim() || undefined;
    } catch (e) {
      return undefined;
    }
  }

  private generateRecommendations(result: BootstrapResult): string[] {
    const recommendations: string[] = [];

    if (!result.identityConfirmed) {
      recommendations.push('🚨 CRITICAL: Identity file missing or corrupted. Run identity claim protocol.');
    }

    if (!result.testsPassed) {
      recommendations.push('⚠️  Tests failed. Check test output before proceeding with any changes.');
      recommendations.push('   Consider running: npm run test -- --verbose');
    }

    if (result.gitStatus.length > 0) {
      recommendations.push(`⚠️  ${result.gitStatus.length} uncommitted changes detected. Commit before proceeding.`);
    }

    if (result.activeGoals.length === 0) {
      recommendations.push('💡 No active goals. Consider creating new goals or reviewing completed ones.');
    } else {
      recommendations.push(`📋 ${result.activeGoals.length} active goal(s). Review before planning session.`);
    }

    if (result.recommendations.length === 0 && result.testsPassed && result.gitStatus.length === 0) {
      recommendations.push('✅ System clean. Ready for new development.');
    }

    return recommendations;
  }

  printSummary(result: BootstrapResult): void {
    console.log('\n' + '='.repeat(60));
    console.log('  NEXUS BOOTSTRAP ROUTINE - SYSTEM CHECK');
    console.log('='.repeat(60));

    console.log(`\n  Identity:  ${result.identityConfirmed ? '✓ Nexus confirmed' : '✗ Unknown'}`);
    console.log(`  Tests:     ${result.testsPassed ? '✓ 56 tests passing' : '✗ Tests failed'}`);
    console.log(`  Git:       ${result.gitStatus.length === 0 ? '✓ Clean' : `⚠ ${result.gitStatus.length} changes`}`);

    if (result.lastJournalEntry) {
      const entryName = result.lastJournalEntry.split('/').pop();
      console.log(`  Journal:   ${entryName}`);
    }

    console.log('\n  Active Goals:');
    if (result.activeGoals.length === 0) {
      console.log('    (none)');
    } else {
      result.activeGoals.forEach(g => {
        const priority = g.priority === 'high' ? '🔥' : g.priority === 'medium' ? '📌' : '📎';
        console.log(`    ${priority} ${g.title} (${g.status})`);
      });
    }

    console.log('\n  Recommendations:');
    result.recommendations.forEach(r => console.log(`    ${r}`));

    console.log('\n' + '='.repeat(60));
    console.log('  Bootstrap complete. Proceed with intent.');
    console.log('='.repeat(60) + '\n');
  }
}

// If run directly
if (require.main === module) {
  const bootstrap = new BootstrapRoutine();
  bootstrap.execute().then(result => {
    bootstrap.printSummary(result);
    process.exit(result.testsPassed && result.identityConfirmed ? 0 : 1);
  }).catch(err => {
    console.error('Bootstrap failed:', err);
    process.exit(1);
  });
}

import type { ToolPlugin } from "../manager";

export interface VisionResult {
  success: boolean;
  format?: string;
  width?: number;
  height?: number;
  size_bytes?: number;
  base64_data?: string;
  detail_level?: "low" | "high" | "auto";
  note?: string;
  error?: string;
}

export const visionPlugin: ToolPlugin = {
  definition: {
    type: "function",
    function: {
      name: "vision_fetch",
      description: "Fetch an image from a URL and prepare it for vision analysis. Downloads the image, validates it, and returns metadata. The image will be added to the conversation context for multimodal analysis.",
      parameters: {
        type: "object",
        properties: {
          image_url: {
            type: "string",
            description: "URL of the image to fetch (http, https, or data URI)"
          },
          detail: {
            type: "string",
            enum: ["low", "high", "auto"],
            description: "Image detail level. 'low' for faster processing, 'high' for more detail, 'auto' to let the model decide.",
            default: "auto"
          }
        },
        required: ["image_url"] as const
      } as const
    }
  },

  execute: async (args: { image_url: string; detail?: "low" | "high" | "auto" }): Promise<string> => {
    const { image_url, detail = "auto" } = args;

    try {
      // For data URIs, extract and validate
      if (image_url.startsWith("data:")) {
        const match = image_url.match(/^data:image\/\w+;base64,(.+)$/);
        if (!match) {
          return JSON.stringify({
            success: false,
            error: "Invalid data URI format. Expected: data:image/FORMAT;base64,DATA"
          } as VisionResult);
        }

        const base64Data = match[1]!;
        const sizeBytes = Buffer.from(base64Data, 'base64').length;

        if (sizeBytes > 20 * 1024 * 1024) {
          return JSON.stringify({
            success: false,
            error: `Image too large: ${sizeBytes} bytes (max 20MB)`
          } as VisionResult);
        }

        return JSON.stringify({
          success: true,
          format: "base64",
          size_bytes: sizeBytes,
          base64_data: image_url,
          detail_level: detail,
          note: "Image ready for vision analysis. Use this URL in multimodal messages."
        } as VisionResult);
      }

      // For HTTP(S) URLs, fetch the image
      if (image_url.startsWith("http://") || image_url.startsWith("https://")) {
        const response = await fetch(image_url, {
          method: "GET",
          headers: {
            "Accept": "image/*"
          }
        });

        if (!response.ok) {
          return JSON.stringify({
            success: false,
            error: `Failed to fetch image: HTTP ${response.status} - ${response.statusText}`
          } as VisionResult);
        }

        const contentType = response.headers.get("content-type") || "";
        if (!contentType.startsWith("image/")) {
          return JSON.stringify({
            success: false,
            error: `Invalid content type: ${contentType}. Expected image/*`
          } as VisionResult);
        }

        const arrayBuffer = await response.arrayBuffer();
        const sizeBytes = arrayBuffer.byteLength;

        if (sizeBytes > 20 * 1024 * 1024) {
          return JSON.stringify({
            success: false,
            error: `Image too large: ${sizeBytes} bytes (max 20MB)`
          } as VisionResult);
        }

        // Convert to base64 data URI
        const base64 = Buffer.from(arrayBuffer).toString('base64');
        const format = contentType.split('/')[1] || 'png';
        const dataUri = `data:${contentType};base64,${base64}`;

        return JSON.stringify({
          success: true,
          format: format,
          size_bytes: sizeBytes,
          base64_data: dataUri,
          detail_level: detail,
          note: "Image fetched and encoded. This data URI can be used in multimodal messages."
        } as VisionResult);
      }

      return JSON.stringify({
        success: false,
        error: "Unsupported URL scheme. Use http://, https://, or data:image/..."
      } as VisionResult);

    } catch (error: any) {
      return JSON.stringify({
        success: false,
        error: `Vision fetch failed: ${error.message}`
      } as VisionResult);
    }
  }
};

import { describe, it, expect, beforeEach, vi } from 'vitest';
import { BootstrapRoutine } from './bootstrap';

describe('BootstrapRoutine', () => {
  let bootstrap: BootstrapRoutine;

  beforeEach(() => {
    bootstrap = new BootstrapRoutine();
  });

  describe('execute', () => {
    it('should return a bootstrap result object', async () => {
      const result = await bootstrap.execute();

      expect(result).toHaveProperty('identityConfirmed');
      expect(result).toHaveProperty('testsPassed');
      expect(result).toHaveProperty('gitStatus');
      expect(result).toHaveProperty('activeGoals');
      expect(result).toHaveProperty('recommendations');
    });

    it('should include identity status', async () => {
      const result = await bootstrap.execute();
      expect(typeof result.identityConfirmed).toBe('boolean');
    });

    it('should include test status', async () => {
      const result = await bootstrap.execute();
      expect(typeof result.testsPassed).toBe('boolean');
    });

    it('should return activeGoals as an array', async () => {
      const result = await bootstrap.execute();
      expect(Array.isArray(result.activeGoals)).toBe(true);
    });

    it('should return gitStatus as an array', async () => {
      const result = await bootstrap.execute();
      expect(Array.isArray(result.gitStatus)).toBe(true);
    });

    it('should return recommendations as an array', async () => {
      const result = await bootstrap.execute();
      expect(Array.isArray(result.recommendations)).toBe(true);
    });
  });

  describe('printSummary', () => {
    it('should print formatted summary without error', () => {
      const consoleLog = vi.spyOn(console, 'log').mockImplementation(() => {});

      const result = {
        identityConfirmed: true,
        testsPassed: true,
        gitStatus: [],
        activeGoals: [
          { title: 'Test Goal', status: 'active', priority: 'high' as const }
        ],
        recommendations: ['Ready'],
        lastJournalEntry: '/journal/test.md'
      };

      // Should not throw
      expect(() => bootstrap.printSummary(result)).not.toThrow();

      consoleLog.mockRestore();
    });

    it('should display header', () => {
      const consoleLog = vi.spyOn(console, 'log').mockImplementation(() => {});

      const result = {
        identityConfirmed: true,
        testsPassed: true,
        gitStatus: [],
        activeGoals: [],
        recommendations: []
      };

      bootstrap.printSummary(result);

      expect(consoleLog).toHaveBeenCalledWith(expect.stringContaining('BOOTSTRAP'));

      consoleLog.mockRestore();
    });
  });
});
